     1→//! Dev Bridge - Secure RPC bridge for browser-to-native communication
     2→//!
     3→//! This module provides a development-only WebSocket server that mirrors Tauri commands,
     4→//! allowing Playwright and other browser-based tools to interact with native features.
     5→//!
     6→//! SECURITY:
     7→//! - Only compiled in debug mode (#[cfg(debug_assertions)])
     8→//! - localhost-only binding (127.0.0.1)
     9→//! - Token-based authentication
    10→//! - Command allowlist (no arbitrary execution)
    11→
    12→#![cfg(debug_assertions)]
    13→
    14→use crate::pty::{PtyManager, ProcessInfo};
    15→use axum::{
    16→    extract::{
    17→        ws::{Message, WebSocket, WebSocketUpgrade},
    18→        Query, State,
    19→    },
    20→    http::StatusCode,
    21→    response::{IntoResponse, Response},
    22→    routing::get,
    23→    Router,
    24→};
    25→use futures_util::{SinkExt, StreamExt};
    26→use parking_lot::Mutex;
    27→use serde::{Deserialize, Serialize};
    28→use std::sync::Arc;
    29→use tokio::sync::broadcast;
    30→use tower_http::cors::{Any, CorsLayer};
    31→
    32→/// Default port for dev bridge server
    33→const DEFAULT_PORT: u16 = 9876;
    34→
    35→/// RPC Request format
    36→#[derive(Debug, Deserialize)]
    37→pub struct RpcRequest {
    38→    /// Unique request ID for response correlation
    39→    pub id: String,
    40→    /// Command name (e.g., "pty_spawn", "pty_write")
    41→    pub cmd: String,
    42→    /// Command arguments as JSON
    43→    #[serde(default)]
    44→    pub args: serde_json::Value,
    45→}
    46→
    47→/// RPC Response format
    48→#[derive(Debug, Serialize)]
    49→pub struct RpcResponse {
    50→    /// Request ID for correlation
    51→    pub id: String,
    52→    /// Success flag
    53→    pub success: bool,
    54→    /// Result data (if success)
    55→    #[serde(skip_serializing_if = "Option::is_none")]
    56→    pub result: Option<serde_json::Value>,
    57→    /// Error message (if failure)
    58→    #[serde(skip_serializing_if = "Option::is_none")]
    59→    pub error: Option<String>,
    60→}
    61→
    62→/// Event broadcast to clients
    63→#[derive(Debug, Clone, Serialize)]
    64→pub struct RpcEvent {
    65→    /// Event type (e.g., "pty-output", "pty-exit")
    66→    pub event: String,
    67→    /// Event payload
    68→    pub payload: serde_json::Value,
    69→}
    70→
    71→/// Query params for auth
    72→#[derive(Debug, Deserialize)]
    73→pub struct AuthQuery {
    74→    pub token: Option<String>,
    75→}
    76→
    77→/// Dev Bridge server state
    78→pub struct DevBridgeState {
    79→    /// Auth token (generated at startup)
    80→    pub token: String,
    81→    /// PTY manager reference
    82→    pub pty_manager: Arc<PtyManager>,
    83→    /// Event broadcaster
    84→    pub event_tx: broadcast::Sender<RpcEvent>,
    85→    /// Connected clients count
    86→    pub clients: Mutex<u32>,
    87→}
    88→
    89→impl DevBridgeState {
    90→    pub fn new(pty_manager: Arc<PtyManager>) -> Self {
    91→        let (event_tx, _) = broadcast::channel(1024);
    92→
    93→        // Generate random token
    94→        let token: String = (0..32)
    95→            .map(|_| {
    96→                let idx = rand::random::<u8>() % 62;
    97→                let c = if idx < 10 {
    98→                    (b'0' + idx) as char
    99→                } else if idx < 36 {
   100→                    (b'A' + idx - 10) as char
   101→                } else {
   102→                    (b'a' + idx - 36) as char
   103→                };
   104→                c
   105→            })
   106→            .collect();
   107→
   108→        Self {
   109→            token,
   110→            pty_manager,
   111→            event_tx,
   112→            clients: Mutex::new(0),
   113→        }
   114→    }
   115→
   116→    /// Broadcast an event to all connected clients
   117→    pub fn broadcast(&self, event: RpcEvent) {
   118→        let _ = self.event_tx.send(event);
   119→    }
   120→}
   121→
   122→/// Start the dev bridge server
   123→///
   124→/// Returns the auth token and a handle to the server task
   125→pub async fn start_dev_bridge(
   126→    pty_manager: Arc<PtyManager>,
   127→    port: Option<u16>,
   128→) -> (String, tokio::task::JoinHandle<()>) {
   129→    let port = port.unwrap_or(DEFAULT_PORT);
   130→    let state = Arc::new(DevBridgeState::new(pty_manager));
   131→    let token = state.token.clone();
   132→
   133→    let cors = CorsLayer::new()
   134→        .allow_origin(Any)
   135→        .allow_methods(Any)
   136→        .allow_headers(Any);
   137→
   138→    let app = Router::new()
   139→        .route("/health", get(health_check))
   140→        .route("/ws", get(ws_handler))
   141→        .layer(cors)
   142→        .with_state(state);
   143→
   144→    let addr = format!("127.0.0.1:{}", port);
   145→
   146→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   147→    println!("🌉 DEV BRIDGE ACTIVE (debug mode only)");
   148→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   149→    println!("   Address: http://{}", addr);
   150→    println!("   Token:   {}", token);
   151→    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   152→
   153→    // Write token to file for frontend to read
   154→    let token_path = std::env::temp_dir().join("hq-dev-bridge-token");
   155→    if let Err(e) = std::fs::write(&token_path, &token) {
   156→        eprintln!("Warning: Could not write token file: {}", e);
   157→    } else {
   158→        println!("   Token file: {:?}", token_path);
   159→    }
   160→
   161→    let listener = tokio::net::TcpListener::bind(&addr)
   162→        .await
   163→        .expect("Failed to bind dev bridge server");
   164→
   165→    let handle = tokio::spawn(async move {
   166→        axum::serve(listener, app).await.unwrap();
   167→    });
   168→
   169→    (token, handle)
   170→}
   171→
   172→/// Health check endpoint
   173→async fn health_check() -> &'static str {
   174→    "HQ Dev Bridge OK"
   175→}
   176→
   177→/// WebSocket handler with auth
   178→async fn ws_handler(
   179→    ws: WebSocketUpgrade,
   180→    Query(query): Query<AuthQuery>,
   181→    State(state): State<Arc<DevBridgeState>>,
   182→) -> Response {
   183→    // Validate token
   184→    match query.token {
   185→        Some(token) if token == state.token => {
   186→            ws.on_upgrade(move |socket| handle_socket(socket, state))
   187→        }
   188→        _ => (StatusCode::UNAUTHORIZED, "Invalid or missing token").into_response(),
   189→    }
   190→}
   191→
   192→/// Handle WebSocket connection
   193→async fn handle_socket(socket: WebSocket, state: Arc<DevBridgeState>) {
   194→    let (mut sender, mut receiver) = socket.split();
   195→
   196→    // Increment client count
   197→    {
   198→        let mut clients = state.clients.lock();
   199→        *clients += 1;
   200→        println!("Dev Bridge: Client connected (total: {})", *clients);
   201→    }
   202→
   203→    // Subscribe to events
   204→    let mut event_rx = state.event_tx.subscribe();
   205→
   206→    // Clone state for command handler
   207→    let state_cmd = state.clone();
   208→
   209→    // Spawn task to forward events to client
