   277→/// Execute a command and return result
   278→async fn execute_command(
   279→    cmd: &str,
   280→    args: &serde_json::Value,
   281→    state: &DevBridgeState,
   282→) -> Result<serde_json::Value, String> {
   283→    match cmd {
   284→        "pty_spawn" => {
   285→            let cmd_str = args["cmd"].as_str().ok_or("Missing 'cmd' argument")?;
   286→            let args_vec: Vec<String> = args["args"]
